import 'package:bookly/Feature/Home/domain/entities/book_entities.dart';import 'package:bookly/Feature/Home/domain/use_cases/home_use_cases.dart';import 'package:flutter_bloc/flutter_bloc.dart';part 'home_state.dart';class HomeCubit extends Cubit<HomeState> {  HomeCubit(this.fetchAllBooksUseCase, this.fetchBooksPicturesUseCase)      : super(HomeInitial());  final FetchAllBooksUseCase fetchAllBooksUseCase;  final FetchBooksPicturesUseCase fetchBooksPicturesUseCase;  static HomeCubit get(context) => BlocProvider.of(context);  Future<void> fetchAllBooks() async {    emit(GetAllBooksLoading());    await fetchAllBooksUseCase.execute().then((value) {      value.fold(          (failure) => emit(GetAllBooksFailure(error: failure.errMessage)),          (books) => emit(GetAllBooksSuccess(books: books)));    });  }  Future<void> fetchBooksPictures() async {    emit(GetBooksPictureLoading());    var result = await fetchBooksPicturesUseCase.execute();    result.fold((failure) {      emit(GetBooksPictureFailure(error: failure.errMessage));    }, (books) {      emit(GetBooksPictureSuccess(books: books));    });  }}